import { useMemo } from 'react';

/**
 * A hook that returns the same value if the identity of the value has not changed
 * This is useful when you want to prevent unnecessary rerenders of a component unless the value has really changed
 *
 * @example
 * // This will always return the same value with a stable reference, because the returned identity is always the same
 * const time = useIdentity(dayjs('2020-01-01'), x => x.unix());
 */
export function useIdentity<T, TRes = T>(
  value: T,
  identityFn: (val: T) => unknown,
  selectorFn?: (val: T) => TRes
): TRes {
  const identity = identityFn(value);

  // biome-ignore lint/correctness/useExhaustiveDependencies: This will work because we don't care about the value itself, but rather the identity of the value
  return useMemo(() => (selectorFn ? selectorFn(value) : (value as unknown as TRes)), [identity]);
}
